#ifndef CC1101_H
#define CC1101_H

#include "esp_err.h"
#include "driver/spi_master.h"

esp_err_t cc1101_init();
esp_err_t cc1101_write_reg(uint8_t reg, uint8_t val);
uint8_t cc1101_read_reg(uint8_t reg);
esp_err_t cc1101_cmd_strobe(uint8_t cmd);
void cc1101_set_rx_mode();
void cc1101_set_tx_mode();
void cc1101_set_idle_mode();
void cc1101_send_slowrf(const char* hex_data);

#define CC1101_WRITE_BURST  0x40
#define CC1101_READ_SINGLE  0x80
#define CC1101_READ_BURST   0xC0

// Status Registers
#define CC1101_PARTNUM      0x30
#define CC1101_VERSION      0x31

// Command Strobes
#define CC1101_SRES         0x30
#define CC1101_SFSTX        0x31
#define CC1101_SXOFF        0x32
#define CC1101_SCAL         0x33
#define CC1101_SRX          0x34
#define CC1101_STX          0x35
#define CC1101_SIDLE        0x36
#define CC1101_SWOR         0x38
#define CC1101_SPWD         0x39
#define CC1101_SFTX         0x3B
#define CC1101_SFRX         0x3C
#define CC1101_SNOP         0x3D

#endif

#include "slowrf.h"
#include "driver/gpio.h"
#include "driver/usb_serial_jtag.h"
#include "esp_timer.h"
#include "esp_log.h"
#include "freertos/FreeRTOS.h"
#include "freertos/queue.h"
#include "culfw_parser.h"

static const char *TAG = "SLOWRF";
static QueueHandle_t pulse_queue;
static int64_t last_time = 0;

static void IRAM_ATTR gpio_isr_handler(void* arg) {
    int64_t current_time = esp_timer_get_time();
    int64_t diff = current_time - last_time;
    last_time = current_time;

    // Simple filter for SlowRF: 200us < duration < 15ms
    if (diff > 200 && diff < 15000) { 
        xQueueSendFromISR(pulse_queue, &diff, NULL);
    }
}

#define SLOWRF_BIT_S_MIN 300
#define SLOWRF_BIT_S_MAX 550
#define SLOWRF_BIT_L_MIN 550
#define SLOWRF_BIT_L_MAX 900
#define SLOWRF_SYNC_MIN  8000

typedef struct {
    uint8_t data[16];
    int byte_cnt;
    int bit_cnt;
    uint8_t current_byte;
} slowrf_decoder_t;

static void reset_decoder(slowrf_decoder_t *dec) {
    memset(dec->data, 0, sizeof(dec->data));
    dec->byte_cnt = 0;
    dec->bit_cnt = 0;
    dec->current_byte = 0;
}

void slowrf_task(void *pvParameters) {
    int64_t pulse;
    slowrf_decoder_t dec;
    reset_decoder(&dec);

    int pulse_in_bit = 0;
    int last_bit = -1;

    while (1) {
        if (xQueueReceive(pulse_queue, &pulse, portMAX_DELAY)) {
            if (pulse > SLOWRF_SYNC_MIN) {
                if (dec.byte_cnt >= 2) {
                    char out[64];
                    int len = snprintf(out, sizeof(out), "F");
                    for (int i = 0; i < dec.byte_cnt; i++) {
                        len += snprintf(out + len, sizeof(out) - len, "%02X", dec.data[i]);
                    }
                    snprintf(out + len, sizeof(out) - len, "\r\n");
                    usb_serial_jtag_write_bytes(out, strlen(out), 0);
                }
                reset_decoder(&dec);
                pulse_in_bit = 0;
            } else {
                int bit = -1;
                // Wider tolerances for noise
                if (pulse >= 250 && pulse <= 550) bit = 0;
                else if (pulse >= 550 && pulse <= 950) bit = 1;

                if (bit != -1) {
                    if (pulse_in_bit == 0) {
                        last_bit = bit;
                        pulse_in_bit = 1;
                    } else {
                        if (bit == last_bit) {
                            // Valid FS20 bit (two identical pulses)
                            dec.current_byte = (dec.current_byte << 1) | bit;
                            dec.bit_cnt++;

                            // FS20: 8 data bits + 1 parity bit = 9 bits
                            if (dec.bit_cnt == 9) {
                                if (dec.byte_cnt < sizeof(dec.data)) {
                                    // Extract 8 bits (the first 8 of the 9)
                                    dec.data[dec.byte_cnt++] = (dec.current_byte >> 1);
                                }
                                dec.current_byte = 0;
                                dec.bit_cnt = 0;
                            }
                        }
                        pulse_in_bit = 0;
                    }
                } else {
                    pulse_in_bit = 0;
                }
            }

            static int loop_cnt = 0;
            if (++loop_cnt > 100) {
                vTaskDelay(1);
                loop_cnt = 0;
            }
        }
    }
}

esp_err_t slowrf_init() {
    pulse_queue = xQueueCreate(256, sizeof(int64_t));

    gpio_config_t io_conf = {
        .intr_type = GPIO_INTR_ANYEDGE,
        .pin_bit_mask = (1ULL << GPIO_GDO0),
        .mode = GPIO_MODE_INPUT,
        .pull_up_en = 0,
        .pull_down_en = 0,
    };
    gpio_config(&io_conf);

    gpio_install_isr_service(0);
    gpio_isr_handler_add(GPIO_GDO0, gpio_isr_handler, NULL);

    // Lowered priority from 15 to 4 (above LED, below parser)
    xTaskCreate(slowrf_task, "slowrf_task", 4096, NULL, 4, NULL);

    return ESP_OK;
}

#include "cc1101.h"
#include "driver/spi_master.h"
#include "driver/gpio.h"
#include "esp_log.h"

static const char *TAG = "CC1101";
static spi_device_handle_t spi;

esp_err_t cc1101_init() {
    spi_bus_config_t buscfg = {
        .miso_io_num = GPIO_MISO,
        .mosi_io_num = GPIO_MOSI,
        .sclk_io_num = GPIO_SCK,
        .quadwp_io_num = -1,
        .quadhd_io_num = -1,
        .max_transfer_sz = 64
    };

    spi_device_interface_config_t devcfg = {
        .clock_speed_hz = 1000000, // 1MHz
        .mode = 0,
        .spics_io_num = GPIO_SS,
        .queue_size = 7,
    };

    esp_err_t ret = spi_bus_initialize(SPI2_HOST, &buscfg, SPI_DMA_CH_AUTO);
    if (ret != ESP_OK) return ret;

    ret = spi_bus_add_device(SPI2_HOST, &devcfg, &spi);
    if (ret != ESP_OK) return ret;

    cc1101_cmd_strobe(CC1101_SRES);
    vTaskDelay(pdMS_TO_TICKS(10));

    uint8_t partnum = cc1101_read_reg(CC1101_PARTNUM | CC1101_READ_SINGLE);
    uint8_t version = cc1101_read_reg(CC1101_VERSION | CC1101_READ_SINGLE);

    ESP_LOGI(TAG, "CC1101 Partnum: 0x%02x, Version: 0x%02x", partnum, version);

    if (version == 0 || version == 0xFF) return ESP_FAIL;

    // Default configuration for SlowRF (OOK/ASK)
    gpio_set_direction(GPIO_433MARKER, GPIO_MODE_INPUT);
    bool is_433 = (gpio_get_level(GPIO_433MARKER) == 0);

    // Common SlowRF Setup (ASK, ~2.4k Baud, etc.)
    cc1101_write_reg(0x02, 0x0D); // IOCFG0: GDO0 Serial Data Output
    cc1101_write_reg(0x00, 0x2E); // IOCFG2: GDO2 High Impedance
    cc1101_write_reg(0x0B, 0x06); // FSCTRL1
    cc1101_write_reg(0x0C, 0x00); // FSCTRL0

    if (is_433) {
        cc1101_write_reg(0x0D, 0x10); // FREQ2
        cc1101_write_reg(0x0E, 0xB1); // FREQ1
        cc1101_write_reg(0x0F, 0x3B); // FREQ0
    } else {
        cc1101_write_reg(0x0D, 0x21); // FREQ2
        cc1101_write_reg(0x0E, 0x62); // FREQ1
        cc1101_write_reg(0x0F, 0x76); // FREQ0
    }

    cc1101_write_reg(0x10, 0xF8); // MDMCFG4
    cc1101_write_reg(0x11, 0x93); // MDMCFG3
    cc1101_write_reg(0x12, 0x30); // MDMCFG2: ASK/OOK, No sync
    cc1101_write_reg(0x13, 0x22); // MDMCFG1
    cc1101_write_reg(0x14, 0xF8); // MDMCFG0
    cc1101_write_reg(0x15, 0x15); // DEVIATN
    cc1101_write_reg(0x18, 0x18); // MCSM0
    cc1101_write_reg(0x19, 0x16); // FOCCFG
    cc1101_write_reg(0x1A, 0x6C); // BSCFG
    cc1101_write_reg(0x1B, 0x03); // AGCCTRL2
    cc1101_write_reg(0x1C, 0x40); // AGCCTRL1
    cc1101_write_reg(0x1D, 0x91); // AGCCTRL0
    cc1101_write_reg(0x21, 0x56); // FREND1
    cc1101_write_reg(0x22, 0x10); // FREND0
    cc1101_write_reg(0x23, 0xE9); // FSCAL3
    cc1101_write_reg(0x24, 0x2A); // FSCAL2
    cc1101_write_reg(0x25, 0x00); // FSCAL1
    cc1101_write_reg(0x26, 0x1F); // FSCAL0

    cc1101_write_reg(0x3E, 0xC0); // PATABLE: For ASK/OOK, first byte is the value for "1"

    cc1101_set_rx_mode();

    return ESP_OK;
}

void cc1101_set_rx_mode() {
    cc1101_cmd_strobe(CC1101_SIDLE);
    cc1101_write_reg(0x02, 0x0D); // IOCFG0: GDO0 Serial Data Output
    gpio_set_direction(GPIO_GDO0, GPIO_MODE_INPUT);
    cc1101_cmd_strobe(CC1101_SRX);
}

void cc1101_set_tx_mode() {
    cc1101_cmd_strobe(CC1101_SIDLE);
    cc1101_write_reg(0x02, 0x0D); // IOCFG0: GDO0 Serial Data Input (actually 0x0D is same pin but CC1101 will use it as input in TX)
    gpio_set_direction(GPIO_GDO0, GPIO_MODE_OUTPUT);
    cc1101_cmd_strobe(CC1101_STX);
}

void cc1101_set_idle_mode() {
    cc1101_cmd_strobe(CC1101_SIDLE);
}

#include "rom/ets_sys.h"

static void fs20_send_bit(int bit) {
    if (bit) {
        gpio_set_level(GPIO_GDO0, 1);
        ets_delay_us(600);
        gpio_set_level(GPIO_GDO0, 0);
        ets_delay_us(600);
    } else {
        gpio_set_level(GPIO_GDO0, 1);
        ets_delay_us(400);
        gpio_set_level(GPIO_GDO0, 0);
        ets_delay_us(400);
    }
}

void cc1101_send_slowrf(const char* hex_data) {
    cc1101_set_tx_mode();
    vTaskDelay(pdMS_TO_TICKS(2)); // Settling

    // Multi-transmit for reliability (standard culfw behavior)
    for (int repeat = 0; repeat < 3; repeat++) {
        // 1. Preamble (13 bits of 0)
        for(int i=0; i<13; i++) fs20_send_bit(0);

        // 2. Sync bit (bit 0)
        fs20_send_bit(0);

        // 3. Data (hex string to bits)
        int hex_len = strlen(hex_data);
        for(int i=0; i<hex_len; i+=2) {
            char h[3] = {hex_data[i], hex_data[i+1], 0};
            uint8_t b = (uint8_t)strtol(h, NULL, 16);
            int parity = 0;
            for(int j=7; j>=0; j--) {
                int bit = (b >> j) & 1;
                fs20_send_bit(bit);
                if (bit) parity++;
            }
            // Parity bit (even parity)
            fs20_send_bit(parity % 2);
        }

        // 4. End bit (bit 0)
        fs20_send_bit(0);

        // Gap between repeats
        ets_delay_us(10000);
    }

    cc1101_set_rx_mode();
}

esp_err_t cc1101_write_reg(uint8_t reg, uint8_t val) {
    spi_transaction_t t = {
        .length = 16,
        .tx_data = {reg, val},
        .flags = SPI_TRANS_USE_TXDATA
    };
    return spi_device_transmit(spi, &t);
}

uint8_t cc1101_read_reg(uint8_t reg) {
    uint8_t tx_data[2] = {reg | CC1101_READ_SINGLE, 0x00};
    uint8_t rx_data[2] = {0, 0};
    spi_transaction_t t = {
        .length = 16,
        .tx_buffer = tx_data,
        .rx_buffer = rx_data,
    };
    spi_device_transmit(spi, &t);
    return rx_data[1];
}

esp_err_t cc1101_cmd_strobe(uint8_t cmd) {
    spi_transaction_t t = {
        .length = 8,
        .tx_data = {cmd},
        .flags = SPI_TRANS_USE_TXDATA
    };
    return spi_device_transmit(spi, &t);
}

